const agentOutput = $input.first().json.output;

// Parse JSON — strip markdown fences if agent wrapped it
let parsed;
try {
  parsed = JSON.parse(agentOutput);
} catch (e) {
  const cleaned = agentOutput.replace(/```json\n?|\n?```/g, '').trim();
  parsed = JSON.parse(cleaned);
}

const generatedAt = new Date().toISOString();
const selectedVibes = parsed.selected_vibes || [];

return parsed.captions.map(c => ({
  json: {
    ID: c.id,
    Vibe: c.vibe,
    Model: c.model,
    Caption: c.caption_text,
    Hashtags: c.hashtags,
    Generated_At: generatedAt,
    Visual_Anchor: c.visual_anchor,
    Selected_Vibes: selectedVibes
  }
}));

const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { historyText: "No previous runs yet." } }];
}
// Take last 3 rows (sheet is append-only, so last = most recent)
const recent = rows.slice(-3).reverse();
const lines = recent.map((row, i) =>
  `- ${i + 1} run(s) ago: ${row.json.selected_vibes}`
);
return [{ json: {
  historyText: "Recent run vibes — DO NOT repeat any of these non-Sale vibes:\n" + lines.join('\n')
} }];
